import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Link } from 'react-router-dom';
import './Dashboard.css';

// API URL configuration
const API_URL = process.env.NODE_ENV === 'production' 
  ? '' 
  : 'http://localhost:5001';

function Dashboard() {
  const [analytics, setAnalytics] = useState(null);
  const [recentTransactions, setRecentTransactions] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchDashboardData();
  }, []);

  const fetchDashboardData = async () => {
    try {
      const [analyticsRes, transactionsRes] = await Promise.all([
        axios.get(`${API_URL}/api/analytics`),
        axios.get(`${API_URL}/api/transactions?limit=5`)
      ]);

      setAnalytics(analyticsRes.data);
      setRecentTransactions(transactionsRes.data.transactions);
    } catch (error) {
      console.error('Error fetching dashboard data:', error);
    }
    setLoading(false);
  };

  if (loading) return <div className="loading">Loading...</div>;

  return (
    <div className="dashboard">
      <div className="dashboard-header">
        <h1>Financial Dashboard</h1>
        <Link to="/transactions" className="btn-primary">
          Add Transaction
        </Link>
      </div>

      {analytics && (
        <div className="summary-cards">
          <div className="summary-card income">
            <h3>Total Income</h3>
            <p className="amount">${analytics.summary.totalIncome.toFixed(2)}</p>
          </div>
          <div className="summary-card expense">
            <h3>Total Expenses</h3>
            <p className="amount">${analytics.summary.totalExpenses.toFixed(2)}</p>
          </div>
          <div className="summary-card savings">
            <h3>Savings</h3>
            <p className="amount">${analytics.summary.savings.toFixed(2)}</p>
          </div>
          <div className="summary-card rate">
            <h3>Savings Rate</h3>
            <p className="amount">{analytics.summary.savingsRate.toFixed(1)}%</p>
          </div>
        </div>
      )}

      <div className="dashboard-content">
        <div className="recent-transactions">
          <h2>Recent Transactions</h2>
          {recentTransactions.length === 0 ? (
            <p>No transactions yet. <Link to="/transactions">Add your first transaction!</Link></p>
          ) : (
            <div className="transactions-list">
              {recentTransactions.map(transaction => (
                <div key={transaction._id} className="transaction-item">
                  <div className="transaction-info">
                    <span className={`type-badge ${transaction.type}`}>
                      {transaction.type}
                    </span>
                    <span className="description">{transaction.description}</span>
                    <span className="category">{transaction.category}</span>
                  </div>
                  <span className={`amount ${transaction.type}`}>
                    ${transaction.amount.toFixed(2)}
                  </span>
                </div>
              ))}
            </div>
          )}
        </div>

        <div className="quick-actions">
          <h2>Quick Actions</h2>
          <div className="action-buttons">
            <Link to="/transactions" className="action-btn">
              View All Transactions
            </Link>
            <Link to="/analytics" className="action-btn">
              View Analytics
            </Link>
          </div>
        </div>
      </div>
    </div>
  );
}

export default Dashboard;