import React, { useState, useEffect } from 'react';
import axios from 'axios';
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  LineElement,
  PointElement,
  ArcElement,
  Title,
  Tooltip,
  Legend,
} from 'chart.js';
import { Bar, Line, Doughnut } from 'react-chartjs-2';
import './Analytics.css';

// API URL configuration
const API_URL = process.env.NODE_ENV === 'production' 
  ? '' 
  : 'http://localhost:5001';

// Register ChartJS components
ChartJS.register(
  CategoryScale,
  LinearScale,
  BarElement,
  LineElement,
  PointElement,
  ArcElement,
  Title,
  Tooltip,
  Legend
);

function Analytics() {
  const [analytics, setAnalytics] = useState(null);
  const [loading, setLoading] = useState(true);
  const [dateRange, setDateRange] = useState({
    startDate: '',
    endDate: ''
  });

  useEffect(() => {
    fetchAnalytics();
  }, []);

  const fetchAnalytics = async (startDate = '', endDate = '') => {
    setLoading(true);
    try {
      const params = new URLSearchParams();
      if (startDate) params.append('startDate', startDate);
      if (endDate) params.append('endDate', endDate);

      const response = await axios.get(`${API_URL}/api/analytics?${params}`);
      setAnalytics(response.data);
    } catch (error) {
      console.error('Error fetching analytics:', error);
    }
    setLoading(false);
  };

  const handleDateFilter = (e) => {
    e.preventDefault();
    fetchAnalytics(dateRange.startDate, dateRange.endDate);
  };

  const clearFilter = () => {
    setDateRange({ startDate: '', endDate: '' });
    fetchAnalytics();
  };

  if (loading) return <div className="loading">Loading analytics...</div>;
  if (!analytics) return <div className="no-data">No data available. Add some transactions to see analytics.</div>;

  // Monthly Trend Chart Data (Bar Chart)
  const monthlyChartData = {
    labels: analytics.monthlyTrend.map(item => item.month),
    datasets: [
      {
        label: 'Income',
        data: analytics.monthlyTrend.map(item => item.income),
        backgroundColor: 'rgba(75, 192, 192, 0.6)',
        borderColor: 'rgba(75, 192, 192, 1)',
        borderWidth: 2,
      },
      {
        label: 'Expenses',
        data: analytics.monthlyTrend.map(item => item.expense),
        backgroundColor: 'rgba(255, 99, 132, 0.6)',
        borderColor: 'rgba(255, 99, 132, 1)',
        borderWidth: 2,
      },
    ],
  };

  // Category Breakdown (Doughnut Chart - Expenses only)
  const expenseCategories = Object.entries(analytics.categoryData)
    .filter(([category, data]) => data.expense > 0);

  const categoryData = {
    labels: expenseCategories.map(([category]) => 
      category.charAt(0).toUpperCase() + category.slice(1)
    ),
    datasets: [
      {
        label: 'Expenses by Category',
        data: expenseCategories.map(([_, data]) => data.expense),
        backgroundColor: [
          '#FF6384', '#36A2EB', '#FFCE56', '#4BC0C0',
          '#9966FF', '#FF9F40', '#8AE2A2', '#C9CBCF',
          '#FF6384', '#36A2EB'
        ],
        borderWidth: 2,
        borderColor: '#fff'
      },
    ],
  };

  // Income vs Expenses Trend (Line Chart)
  const trendChartData = {
    labels: analytics.monthlyTrend.map(item => item.month),
    datasets: [
      {
        label: 'Income Trend',
        data: analytics.monthlyTrend.map(item => item.income),
        borderColor: 'rgba(75, 192, 192, 1)',
        backgroundColor: 'rgba(75, 192, 192, 0.1)',
        tension: 0.4,
        fill: true
      },
      {
        label: 'Expenses Trend',
        data: analytics.monthlyTrend.map(item => item.expense),
        borderColor: 'rgba(255, 99, 132, 1)',
        backgroundColor: 'rgba(255, 99, 132, 0.1)',
        tension: 0.4,
        fill: true
      },
    ],
  };

  // Chart options
  const barChartOptions = {
    responsive: true,
    plugins: {
      legend: {
        position: 'top',
      },
      title: {
        display: true,
        text: 'Monthly Income vs Expenses',
      },
    },
    scales: {
      y: {
        beginAtZero: true,
        ticks: {
          callback: function(value) {
            return '$' + value;
          }
        }
      }
    }
  };

  const doughnutOptions = {
    responsive: true,
    plugins: {
      legend: {
        position: 'bottom',
      },
      title: {
        display: true,
        text: 'Expenses by Category',
      },
    },
  };

  const lineChartOptions = {
    responsive: true,
    plugins: {
      legend: {
        position: 'top',
      },
      title: {
        display: true,
        text: 'Income & Expenses Trend',
      },
    },
    scales: {
      y: {
        beginAtZero: true,
        ticks: {
          callback: function(value) {
            return '$' + value;
          }
        }
      }
    }
  };

  return (
    <div className="analytics">
      <div className="analytics-header">
        <h1>Financial Analytics</h1>
        <form onSubmit={handleDateFilter} className="date-filter">
          <div className="filter-inputs">
            <input
              type="date"
              value={dateRange.startDate}
              onChange={(e) => setDateRange({...dateRange, startDate: e.target.value})}
              placeholder="Start Date"
            />
            <span>to</span>
            <input
              type="date"
              value={dateRange.endDate}
              onChange={(e) => setDateRange({...dateRange, endDate: e.target.value})}
              placeholder="End Date"
            />
          </div>
          <div className="filter-buttons">
            <button type="submit" className="btn-primary">Apply Filter</button>
            <button type="button" onClick={clearFilter} className="btn-secondary">
              Clear
            </button>
          </div>
        </form>
      </div>

      {/* Summary Cards */}
      <div className="analytics-summary">
        <div className="summary-item">
          <h3>Total Income</h3>
          <p className="income">${analytics.summary.totalIncome.toFixed(2)}</p>
        </div>
        <div className="summary-item">
          <h3>Total Expenses</h3>
          <p className="expense">${analytics.summary.totalExpenses.toFixed(2)}</p>
        </div>
        <div className="summary-item">
          <h3>Net Savings</h3>
          <p className={`savings ${analytics.summary.savings < 0 ? 'negative' : ''}`}>
            ${analytics.summary.savings.toFixed(2)}
          </p>
        </div>
        <div className="summary-item">
          <h3>Savings Rate</h3>
          <p className="rate">
            {analytics.summary.savingsRate.toFixed(1)}%
          </p>
        </div>
      </div>

      {/* Charts Grid */}
      <div className="charts-grid">
        <div className="chart-container">
          <Bar data={monthlyChartData} options={barChartOptions} />
        </div>
        
        <div className="chart-container">
          <Doughnut data={categoryData} options={doughnutOptions} />
        </div>
        
        <div className="chart-container full-width">
          <Line data={trendChartData} options={lineChartOptions} />
        </div>
      </div>

      {/* Category Breakdown Table */}
      <div className="category-breakdown">
        <h2>Category Breakdown</h2>
        <div className="category-table">
          <div className="table-header">
            <span>Category</span>
            <span>Income</span>
            <span>Expenses</span>
            <span>Net</span>
          </div>
          {Object.entries(analytics.categoryData).map(([category, data]) => (
            <div key={category} className="table-row">
              <span className="category-name">
                {category.charAt(0).toUpperCase() + category.slice(1)}
              </span>
              <span className="income-amount">
                ${data.income.toFixed(2)}
              </span>
              <span className="expense-amount">
                ${data.expense.toFixed(2)}
              </span>
              <span className={`net-amount ${(data.income - data.expense) < 0 ? 'negative' : ''}`}>
                ${(data.income - data.expense).toFixed(2)}
              </span>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

export default Analytics;